insert into proof_kits (slug, name, partner, customer, industry, use_case, status, summary, demo_path, repo_url) values
  ('semiconductor-predictive-maintenance', 'Semiconductor predictive maintenance — edge AI', 'Technologent', 'Microchip Technology', 'Semiconductor manufacturing', 'OT telemetry -> Losant Gateway Edge Agent -> on-prem inference (health score + RUL + sensor attribution) -> ops dashboard, with raw telemetry held inside the fab and only derived scores allowed to leave.', 'built-and-verified', 'The fully-worked reference Proof Kit: a runnable minimal-footprint MVP plus the partner hand-off. Losant (SUSE Industrial Edge) is a first-class tier of the running demo, and Rancher is wired via an MCP server with live Fleet GitOps.', 'reference-kits/semiconductor-predictive-maintenance/demo', 'https://github.com/MetalRoosterSimulation/edge-proof-factory');
