insert into scale_up_stages (kit_slug, stage_number, title, body_md, sort_order) values
  ('semiconductor-predictive-maintenance', 0, 'The laptop demo (this kit)', 'Single-node k3s (k3d), all-open images, CPU only. Proves the pattern end to end. [P] Run `make up`; walk the customer through a live fault + the governance boundary — no customer hardware, no entitlement, no fab access needed. Exit: the customer agrees the pattern fits a named tool/zone.', 0),
  ('semiconductor-predictive-maintenance', 1, 'One real edge box (PILOT)', 'Move the same workloads onto one physical edge node in one fab zone. [P] Build a SUSE Edge boot image with Edge Image Builder (SL Micro 6.2 + K3s single-server + the kit''s manifests, air-gapped). [P] Deploy the Losant Gateway Edge Agent against the zone''s real OPC UA / Modbus feeds. [P/S] Stand up the inference tier — size the GPU here, not before, if SUSE AI is needed. [P] Add SUSE Security (NeuVector) All-in-One. [C] Provide the edge node and OT network path. Exit: real sensor data scored on real hardware; offline buffering and the governance boundary verified with the customer''s security team.', 1),
  ('semiconductor-predictive-maintenance', 2, 'Production hardening, one zone (ROLL OUT)', '[P] Decide HA now — rebuild on K3s embedded-etcd (3 nodes) or RKE2 with SUSE Storage (Longhorn) if the zone needs it; the datastore is baked into the image and cannot be a config flip later. [P] Stand up Rancher Prime as the management cluster; import the edge cluster (downstream agents dial out, no inbound firewall rule to the fab). [P] Put the kit manifests in Git; deploy via Fleet. Exit: the zone runs on the SUSE-supported stack, fleet-managed, GitOps-driven.', 2),
  ('semiconductor-predictive-maintenance', 3, 'Scale to the fab / many sites (DAY 2 & SCALE)', '[P] Onboard new nodes/zones with Elemental phone-home — no per-site hands-on. [P] Roll the same Fleet GitRepo to a ClusterGroup; new sites converge automatically (renewal grows per site, not just per year). [P] Day-2: Upgrade Controller for staged OS + K8s upgrades; Losant cross-site dashboards. [S] Deal-registration and support wrap across the fleet. Exit: steady-state managed fleet; each new tool/zone is a repeatable unit.', 3);
