insert into ledger_phases (phase_number, title, status, body_md, done_date) values
  (0, 'Research swarm', 'done', 'Four agents read the two sibling factories, the shared suse-brain.md (Edge/AI product facts + version matrix), and the partner motion/economics. Confirmed the gap: both factories produce paper; no runnable MVP or hand-off existed anywhere in ~/Work. Semiconductor predictive-maintenance chosen as the reference use case (Technologent / Microchip Technology).', null),
  (1, 'The runnable MVP (reference kit)', 'done', 'Stood up a real single-node k3s cluster (k3d, v1.35.5). Built the edge-inference model (EWMA-smoothed multivariate control chart, Hotelling T^2 / Mahalanobis SPC, frozen Welford baseline, health score + trend-extrapolated RUL + sensor attribution — pure Python/stdlib, 9/9 unit tests, CPU-only), the sensor-simulator (synthetic plasma-etch telemetry with three fault signatures), and a self-contained ops dashboard. Verified end to end live: healthy fleet reads 6x100; injected fault degrades WATCH -> WARNING -> CRITICAL with RUL counting to 0 and correct sensor attribution.', null),
  (2, 'Losant / SUSE Industrial Edge as a first-class tier', 'done', 'Inserted a gateway-edge-agent (Losant GEA) tier as the single governed egress point: raw OT telemetry -> normalize + offline-buffer -> inference -> derived health -> gateway forwards only derived scores to Losant via the real losant-mqtt SDK. Raw telemetry structurally cannot leave. Verified live: gateway withheld 100% of raw frames in air-gapped mode.', null),
  (3, 'SUSE AI profile', 'done', '`make ai` adds Ollama + Open WebUI (real Application Collection components) and an on-prem /api/explain/<tool> endpoint with a graceful fallback when the AI tier is off. Optional profile — the base kit stays CPU/laptop-class.', null),
  (4, 'Rancher MCP server', 'done', 'Built integrations/rancher-mcp-server/ — a Node/stdio MCP server with 10 tools (list clusters/nodes/projects/namespaces/workloads/fleet, deploy-via-Fleet, import-cluster). Mock mode for offline testing; selftest green on the full stdio handshake.', null),
  (5, 'Hand-off kit + factory scaffolding', 'done', 'Wrote the hand-off kit (00 runbook, 01 component map, 02 scale-up path, 03 production footprint) and the reusable factory machine: START-HERE, CLAUDE.md, RUN.md, docs (project-brief, suse-edge-ai-stack, handoff-doctrine, footprint-rules), templates, and tools/validate_kit.py. Verification: model unit tests 9/9, validate_kit.py 15 pass / 0 warn / 0 fail, Rancher MCP selftest all pass, cold make up end-to-end with live fault + governance proof.', null),
  (6, 'Live Rancher wiring', 'done', 'Connected to a local Rancher Community v2.13.3 instance. Debugged two 401''ing tokens (missing token- prefix); the client and wire-rancher.sh now auto-add the prefix. Imported the k3d edge-mvp cluster into Rancher; verified via the MCP server in real mode that rancher_list_clusters shows edge-mvp active and rancher_list_workloads reads all four kit deployments 1/1 through Rancher''s k8s proxy.', '2026-07-23'),
  (7, 'Fleet GitOps + public repo + run guide', 'done', 'Published the factory to github.com/MetalRoosterSimulation/edge-proof-factory. Created a Fleet GitRepo targeting the imported cluster. Resolved a Helm-adoption ownership conflict by deleting the hand-applied namespace and force-syncing. Fleet redeployed cleanly: readyClusters 1/1, genuinely GitOps-owned. Added HOW-TO-RUN-THIS-DEMO.md.', '2026-07-23'),
  (8, 'Durable re-import', 'done', 'Fixed two re-import failure modes: added fleet.yaml with helm.takeOwnership so Fleet adopts resources a local make up already deployed, and rewrote wire-rancher.sh to detect and clean up an orphaned cluster object before re-importing. Verified end to end: tore down and rebuilt the k3d cluster, ran wire-rancher.sh once, reached 1/1 with confirmed adoption (pods kept their pre-Fleet age and gained Helm labels).', '2026-07-23'),
  (9, 'SUSE AI tier under Fleet + explain endpoint', 'done', 'Fixed a Fleet bundle-scoping failure (a GitRepo path can''t reference ../base) by making k8s/ai self-contained and additive with its own Helm release. /api/explain now returns a clear ''AI tier not reachable, run make ai'' note instead of a raw errno. Verified live: injected an rf_match_drift fault and /api/explain/etch-03 returned a real qwen2.5:0.5b explanation naming the anomaly, on-prem, no data leaving the cluster.', '2026-07-23'),
  (10, 'Factory Portal — Vercel + Supabase', 'done', 'Built a read-only Next.js 16 portal (this app) that surfaces the proof kit catalog, component maps, scale-up paths, footprint specs, and this build ledger from a dedicated Supabase Postgres project, deployed to Vercel. The k3s/Rancher demo itself is unchanged and cannot run on Vercel (serverless has no persistent cluster) — the portal is a presentation layer on top, not a replacement. Schema, seed data (transcribed from the existing handoff docs and this ledger, not invented), RLS policies, and the full test suite were built and verified against a local Supabase stack before any cloud resources were requested. Research/competitor-analysis phase was explicitly dropped from scope by user direction; the portal is being built directly. Live: Supabase project "edge-ai-demo" (ref vpdtwiyvatpwzkapvmcl, us-east-1, free tier) provisioned via the Supabase MCP server (OAuth, no token pasted anywhere); schema + seed applied and verified (zero security advisories). Initially deployed to Vercel via the deploy_to_vercel MCP tool (a one-shot file upload) at https://edge-ai-demo.vercel.app. Later upgraded to git-integrated CI: connected the Vercel project to github.com/MetalRoosterSimulation/edge-proof-factory, set NEXT_PUBLIC_SUPABASE_URL/ANON_KEY as Production+Preview env vars via `vercel env add` (CLI login is an email link, no token pasted), and pushed. First git-triggered build failed — "Couldn''t find any `pages` or `app` directory" — because the project''s Root Directory defaulted to the repo root, not `portal/`; fixed via a direct PATCH to the Vercel REST API (`rootDirectory: "portal"`) using the CLI''s own cached auth token, since neither the MCP server nor `vercel project update` exposes that setting. Next push built clean and served real Postgres data — confirmed by fetching /, /ledger, and /kits/semiconductor-predictive-maintenance directly against the new deployment ID.', '2026-07-23'),
  (11, 'The working demo ON Vercel: /demo in-browser simulation', 'done', 'Phase 10 put the documentation on Vercel; this phase put the **working demo** there. A five-agent research swarm ran first: Vercel has no always-on compute primitive (300s function cap and daily-only cron on Hobby), so a server-driven telemetry feed was rejected; nobody in the predictive-maintenance market (Augury, C3 AI, Sight Machine, Siemens, PTC — or SUSE itself) offers a no-signup, live, fault-injectable public demo, which made that exact combination the target.
insert into open_threads (description, status) values
  ('Additional reference kits (other use-case-library patterns) on demand via RUN.md.', 'open'),
  ('Portal is served via a one-shot Vercel file deploy (MCP deploy_to_vercel), not git-integrated CI, and has no custom domain. Recommended durable follow-up: Import Git Repository in the Vercel dashboard to connect it to github.com/MetalRoosterSimulation/edge-proof-factory (root directory portal/) so future commits auto-deploy, and add NEXT_PUBLIC_SUPABASE_URL/ANON_KEY as dashboard env vars at that point (the Vercel MCP server has no env-var API).', 'resolved'),
  ('Vercel plan for edge-ai-demo: if the account is on Hobby, partner-facing (commercial) use sits outside Hobby''s non-commercial fair-use terms — decide whether to move the project to a Pro team (~$20/mo; also lifts the 300s function and daily-cron caps).', 'open'),
  ('ANTHROPIC_API_KEY not yet set on the Vercel project — until it is added (Vercel dashboard → edge-ai-demo → Settings → Environment Variables, Production + Preview), the demo''s Explain (AI) and Fab Assistant features show the graceful "not configured" note; everything else works without it.', 'open');
